import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GenerationMode, VideoGenerationConfig, VideoFilter } from '../types';

interface ImageDisplayProps {
  isLoading: boolean;
  loadingMessage: string;
  generatedMedia: string | null;
  setGeneratedMedia: (url: string | null) => void;
  error: string | null;
  mode: GenerationMode;
  videoConfig?: VideoGenerationConfig;
}

interface EditState {
  brightness: number;
  saturation: number;
  isCroppedToSquare: boolean;
}

interface VideoEditState {
  trimStart: number;
  trimEnd: number;
  playbackRate: number;
  filter: VideoFilter;
}

const filterMap: Record<VideoFilter, string> = {
  [VideoFilter.NONE]: 'none',
  [VideoFilter.GRAYSCALE]: 'grayscale(100%)',
  [VideoFilter.SEPIA]: 'sepia(100%)',
  [VideoFilter.INVERT]: 'invert(100%)',
  [VideoFilter.VINTAGE]: 'sepia(60%) contrast(75%) brightness(120%) saturate(120%)',
  [VideoFilter.DREAMY]: 'saturate(150%) contrast(110%) brightness(110%) blur(0.5px)',
};

const getAspectRatioClass = (mode: GenerationMode, isCroppedToSquare = false, videoConfig?: VideoGenerationConfig) => {
    if (isCroppedToSquare) return 'aspect-square';
    switch (mode) {
        case GenerationMode.CARTOON:
        case GenerationMode.SOCIAL:
            return 'aspect-square';
        case GenerationMode.VERTICAL_STORY:
        case GenerationMode.STORY_IMAGE:
            return 'aspect-[9/16]';
        case GenerationMode.VIDEO:
             if (videoConfig) {
                switch (videoConfig.aspectRatio) {
                    case '9:16': return 'aspect-[9/16]';
                    case '1:1': return 'aspect-square';
                    case '16:9':
                    default: return 'aspect-video';
                }
            }
            return 'aspect-video';
        case GenerationMode.THUMBNAIL:
        default:
            return 'aspect-video';
    }
};

const Placeholder: React.FC<{ mode: GenerationMode; videoConfig?: VideoGenerationConfig }> = ({ mode, videoConfig }) => {
    const aspectRatioClass = getAspectRatioClass(mode, false, videoConfig);

    return (
        <div className={`w-full ${aspectRatioClass} bg-gray-800/50 rounded-xl border-2 border-dashed border-gray-600 flex flex-col items-center justify-center p-8 text-center`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-gray-500 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
            <h3 className="text-xl font-semibold text-white">Your generated content will appear here</h3>
            <p className="text-gray-400 mt-2">Fill out the details on the left and click "Generate" to see the magic happen.</p>
        </div>
    );
};

const Spinner: React.FC<{ mode: GenerationMode; message: string; videoConfig?: VideoGenerationConfig }> = ({ mode, message, videoConfig }) => {
  const aspectRatioClass = getAspectRatioClass(mode, false, videoConfig);

  return (
    <div className={`w-full ${aspectRatioClass} bg-gray-800/50 rounded-xl flex flex-col items-center justify-center p-8 text-center`}>
      <div className="w-16 h-16 border-4 border-dashed rounded-full animate-spin border-indigo-500"></div>
      <p className="mt-4 text-lg font-semibold text-white">{message}</p>
      <p className="text-gray-400">The AI is working its magic. This may take a moment.</p>
    </div>
  );
}

const EditToolbar: React.FC<{
  activeEdits: EditState;
  onEditChange: (newState: EditState) => void;
  onCommit: () => void;
  onSave: () => void;
  onCancel: () => void;
  onUndo: () => void;
  onRedo: () => void;
  canUndo: boolean;
  canRedo: boolean;
}> = ({ activeEdits, onEditChange, onCommit, onSave, onCancel, onUndo, onRedo, canUndo, canRedo }) => {
  const handleToggleSquare = () => {
    onEditChange({ ...activeEdits, isCroppedToSquare: !activeEdits.isCroppedToSquare });
    // Toggle actions commit immediately
    setTimeout(onCommit, 0);
  };

  return (
    <div className="w-full max-w-xl bg-gray-800 p-4 rounded-xl shadow-lg space-y-4">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-gray-300">Brightness: {activeEdits.brightness}%</label>
          <input 
            type="range" 
            min="0" 
            max="200" 
            value={activeEdits.brightness} 
            onChange={(e) => onEditChange({ ...activeEdits, brightness: Number(e.target.value) })} 
            onMouseUp={onCommit}
            onTouchEnd={onCommit}
            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-300">Saturation: {activeEdits.saturation}%</label>
          <input 
            type="range" 
            min="0" 
            max="200" 
            value={activeEdits.saturation} 
            onChange={(e) => onEditChange({ ...activeEdits, saturation: Number(e.target.value) })} 
            onMouseUp={onCommit}
            onTouchEnd={onCommit}
            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
          />
        </div>
      </div>
      <div className="flex items-center justify-between gap-2 flex-wrap">
        <button 
          onClick={handleToggleSquare} 
          className={`flex-grow px-4 py-2 text-sm font-semibold rounded-lg transition-colors ${activeEdits.isCroppedToSquare ? 'bg-indigo-600 text-white' : 'bg-gray-700 hover:bg-gray-600'}`}
        >
          {activeEdits.isCroppedToSquare ? '✓ Square Crop' : 'Crop to Square'}
        </button>
        <div className="flex gap-2">
          <button onClick={onUndo} disabled={!canUndo} title="Undo" className="px-4 py-2 text-sm font-semibold bg-gray-700 text-white rounded-lg hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" /></svg>
          </button>
          <button onClick={onRedo} disabled={!canRedo} title="Redo" className="px-4 py-2 text-sm font-semibold bg-gray-700 text-white rounded-lg hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
          </button>
        </div>
        <button onClick={onSave} className="flex-grow px-4 py-2 text-sm font-semibold bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors">Save</button>
        <button onClick={onCancel} className="flex-grow px-4 py-2 text-sm font-semibold bg-gray-600 text-white rounded-lg hover:bg-gray-500 transition-colors">Cancel</button>
      </div>
    </div>
  );
};

const VideoEditToolbar: React.FC<{
  editState: VideoEditState;
  onEditChange: (newState: Partial<VideoEditState>) => void;
  onApply: () => void;
  onCancel: () => void;
  onReset: () => void;
  maxDuration: number;
}> = ({ editState, onEditChange, onApply, onCancel, onReset, maxDuration }) => {
  const formatTime = (time: number) => time.toFixed(2);

  const handleTrimStartChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newStart = Number(e.target.value);
    if (newStart < editState.trimEnd) {
      onEditChange({ trimStart: newStart });
    }
  };

  const handleTrimEndChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newEnd = Number(e.target.value);
    if (newEnd > editState.trimStart) {
      onEditChange({ trimEnd: newEnd });
    }
  };

  return (
    <div className="w-full max-w-xl bg-gray-800 p-4 rounded-xl shadow-lg space-y-4">
      <div>
        <label className="block text-sm font-medium text-gray-300 mb-2">Trim Video</label>
        <div className="space-y-2">
            <div>
              <label className="flex justify-between text-xs font-medium text-gray-400">
                <span>Start Time</span>
                <span>{formatTime(editState.trimStart)}s</span>
              </label>
              <input type="range" min="0" max={maxDuration} step="0.1" value={editState.trimStart} onChange={handleTrimStartChange} className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"/>
            </div>
            <div>
              <label className="flex justify-between text-xs font-medium text-gray-400">
                <span>End Time</span>
                <span>{formatTime(editState.trimEnd)}s</span>
              </label>
              <input type="range" min="0" max={maxDuration} step="0.1" value={editState.trimEnd} onChange={handleTrimEndChange} className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"/>
            </div>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label htmlFor="playbackRate" className="block text-sm font-medium text-gray-300 mb-1">Playback Speed</label>
          <select id="playbackRate" value={editState.playbackRate} onChange={e => onEditChange({ playbackRate: Number(e.target.value)})} className="w-full bg-gray-700 border border-gray-600 text-white rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition">
            {[0.5, 0.75, 1, 1.25, 1.5, 2].map(rate => <option key={rate} value={rate}>{rate}x</option>)}
          </select>
        </div>
        <div>
          <label htmlFor="filter" className="block text-sm font-medium text-gray-300 mb-1">Filter</label>
          <select id="filter" value={editState.filter} onChange={e => onEditChange({ filter: e.target.value as VideoFilter })} className="w-full bg-gray-700 border border-gray-600 text-white rounded-lg p-2 text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition">
            {Object.values(VideoFilter).map(f => <option key={f} value={f}>{f}</option>)}
          </select>
        </div>
      </div>
      <div className="flex items-center justify-end gap-2 flex-wrap">
        <button onClick={onReset} className="px-4 py-2 text-sm font-semibold bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors">Reset</button>
        <button onClick={onCancel} className="px-4 py-2 text-sm font-semibold bg-gray-600 text-white rounded-lg hover:bg-gray-500 transition-colors">Cancel</button>
        <button onClick={onApply} className="px-4 py-2 text-sm font-semibold bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors">Apply & Close</button>
      </div>
    </div>
  );
};


