export const ImageDisplay: React.FC<ImageDisplayProps> = ({ isLoading, loadingMessage, generatedMedia, setGeneratedMedia, error, mode, videoConfig }) => {
  const isVideo = mode === GenerationMode.VIDEO;

  // Image Editing state
  const [isEditing, setIsEditing] = useState(false);
  const [editHistory, setEditHistory] = useState<EditState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [activeEdits, setActiveEdits] = useState<EditState>(INITIAL_EDIT_STATE);

  const canUndo = historyIndex > 0;
  const canRedo = historyIndex < editHistory.length - 1;

  // Video state
  const [isPlaying, setIsPlaying] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [videoProgress, setVideoProgress] = useState(0);
  const [videoDuration, setVideoDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [areControlsVisible, setAreControlsVisible] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Video Editing state
  const [isVideoEditing, setIsVideoEditing] = useState(false);
  const [videoEditState, setVideoEditState] = useState<VideoEditState>({
    trimStart: 0,
    trimEnd: 0,
    playbackRate: 1,
    filter: VideoFilter.NONE,
  });
  const [initialVideoEditState, setInitialVideoEditState] = useState<VideoEditState | null>(null);


  const videoRef = useRef<HTMLVideoElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);
  const videoContainerRef = useRef<HTMLDivElement>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  const aspectRatioClass = getAspectRatioClass(mode, isEditing && activeEdits.isCroppedToSquare, videoConfig);

  const resetEditingState = useCallback(() => {
    setIsEditing(false);
    setEditHistory([]);
    setHistoryIndex(-1);
    setActiveEdits(INITIAL_EDIT_STATE);
  }, []);

  useEffect(() => {
    resetEditingState();
    setIsPlaying(false);
    setIsVideoEditing(false);
    if (videoRef.current) {
      videoRef.current.style.filter = 'none';
      videoRef.current.playbackRate = 1;
      videoRef.current.onloadedmetadata = () => {
        if(videoRef.current) {
          const duration = videoRef.current.duration;
          setVideoDuration(duration);
          setVideoEditState({
            trimStart: 0,
            trimEnd: duration,
            playbackRate: 1,
            filter: VideoFilter.NONE,
          });
        }
      };
    }
  }, [generatedMedia, resetEditingState]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.playbackRate = videoEditState.playbackRate;
      videoRef.current.style.filter = filterMap[videoEditState.filter];
    }
  }, [videoEditState]);

  const handleStartEditing = () => {
    setEditHistory([INITIAL_EDIT_STATE]);
    setHistoryIndex(0);
    setActiveEdits(INITIAL_EDIT_STATE);
    setIsEditing(true);
  };

  const handleEditChange = (newState: EditState) => {
    setActiveEdits(newState);
  };

  const handleCommitEdit = () => {
    if (historyIndex >= 0 && JSON.stringify(editHistory[historyIndex]) === JSON.stringify(activeEdits)) {
      return;
    }
    const newHistory = editHistory.slice(0, historyIndex + 1);
    newHistory.push({ ...activeEdits });
    setEditHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  };

  const handleUndo = () => { 
    if (canUndo) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setActiveEdits({ ...editHistory[newIndex] });
    }
  };

  const handleRedo = () => { 
    if (canRedo) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setActiveEdits({ ...editHistory[newIndex] });
    }
  };

  const handleResetFilters = () => {
    setActiveEdits(INITIAL_EDIT_STATE);
    handleCommitEdit();
  };

  const handleSaveChanges = () => {
    if (!imageRef.current || !generatedMedia) return;
    const img = imageRef.current;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { brightness, saturation, contrast, blur, hueRotate, sepia, invert, grayscale, warmth, vignette, isCroppedToSquare } = activeEdits;

    // Construct filter string
    const filterString = `brightness(${brightness}%) saturate(${saturation}%) contrast(${contrast}%) blur(${blur}px) hue-rotate(${hueRotate}deg) sepia(${sepia}%) invert(${invert}%) grayscale(${grayscale}%)`;

    if (isCroppedToSquare) {
      const size = Math.min(img.naturalWidth, img.naturalHeight);
      canvas.width = size;
      canvas.height = size;
      const sx = (img.naturalWidth - size) / 2;
      const sy = (img.naturalHeight - size) / 2;
      ctx.filter = filterString;
      ctx.drawImage(img, sx, sy, size, size, 0, 0, size, size);
    } else {
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      ctx.filter = filterString;
      ctx.drawImage(img, 0, 0);
    }

    // Apply warmth/temperature (simulated with semi-transparent overlay)
    if (warmth !== 0) {
      ctx.globalCompositeOperation = 'soft-light';
      ctx.fillStyle = warmth > 0 ? `rgba(255, 165, 0, ${Math.abs(warmth) / 200})` : `rgba(0, 100, 255, ${Math.abs(warmth) / 200})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
    }

    // Apply Vignette
    if (vignette > 0) {
      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, Math.sqrt((canvas.width/2)**2 + (canvas.height/2)**2)
      );
      gradient.addColorStop(0, 'rgba(0,0,0,0)');
      gradient.addColorStop(1, `rgba(0,0,0,${vignette / 100})`);
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    const newDataUrl = canvas.toDataURL('image/jpeg', 0.95);
    setGeneratedMedia(newDataUrl);
    resetEditingState();
  };

  // Video player handlers
  const handleTogglePlay = () => { if (videoRef.current) videoRef.current.paused ? videoRef.current.play() : videoRef.current.pause(); };
  const handleVideoPlay = () => setIsPlaying(true);
  const handleVideoPauseOrEnd = () => setIsPlaying(false);

  const handleTimeUpdate = () => { 
    if (videoRef.current) {
      const currentTime = videoRef.current.currentTime;
      setVideoProgress(currentTime);
      const isTrimmed = videoEditState.trimEnd < videoDuration;
      if (isTrimmed && currentTime >= videoEditState.trimEnd) {
        videoRef.current.currentTime = videoEditState.trimStart;
        if (!videoRef.current.paused) videoRef.current.play();
      }
    } 
  };

  const handleLoadedMetadata = () => { 
    if (videoRef.current) {
        const duration = videoRef.current.duration;
        setVideoDuration(duration);
        setVideoEditState(prev => ({ ...prev, trimEnd: duration }));
    }
  };
  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => { if (videoRef.current) videoRef.current.currentTime = Number(e.target.value); };
  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (videoRef.current) {
        const newVolume = Number(e.target.value);
        videoRef.current.volume = newVolume;
        setVolume(newVolume);
        if (newVolume > 0) {
            videoRef.current.muted = false;
            setIsMuted(false);
        }
    }
  };
  const handleToggleMute = () => { if (videoRef.current) videoRef.current.muted = !videoRef.current.muted; setIsMuted(prev => !prev); };
  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) videoContainerRef.current?.requestFullscreen();
    else document.exitFullscreen();
  };
  const showControls = useCallback(() => {
    if (controlsTimeoutRef.current) clearTimeout(controlsTimeoutRef.current);
    setAreControlsVisible(true);
    controlsTimeoutRef.current = window.setTimeout(() => setAreControlsVisible(false), 3000);
  }, []);

  useEffect(() => {
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const formatTime = (timeInSeconds: number) => {
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = Math.floor(timeInSeconds % 60);
    return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
  };

  const handleDownload = async () => {
    if (!generatedMedia) return;
    setIsDownloading(true);
    try {
      const fileName = isVideo ? 'ai-video-export.mp4' : 'ai-artwork-export.jpeg';
      let downloadUrl = generatedMedia;
      let isBlobUrl = false;
      if (isVideo) {
        const response = await fetch(generatedMedia);
        if (!response.ok) throw new Error(`Failed to fetch video: ${response.statusText}`);
        const blob = await response.blob();
        downloadUrl = URL.createObjectURL(blob);
        isBlobUrl = true;
      }
      const link = document.createElement('a');
      link.href = downloadUrl;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      if (isBlobUrl) URL.revokeObjectURL(downloadUrl);
    } catch (e) { console.error('Download failed:', e); } 
    finally { setIsDownloading(false); }
  };

  // Video Editing handlers
  const handleStartVideoEditing = () => {
    setInitialVideoEditState(videoEditState);
    setIsVideoEditing(true);
  };

  const handleVideoEditChange = (newState: Partial<VideoEditState>) => {
    setVideoEditState(prev => ({...prev, ...newState}));
  };

  const handleApplyVideoEdits = () => {
    setIsVideoEditing(false);
  };

  const handleCancelVideoEdits = () => {
    if (initialVideoEditState) {
        setVideoEditState(initialVideoEditState);
    }
    setIsVideoEditing(false);
  };

  const handleResetVideoEdits = () => {
    setVideoEditState({
      trimStart: 0,
      trimEnd: videoDuration,
      playbackRate: 1,
      filter: VideoFilter.NONE,
    });
  };

  const imageStyle = { 
    filter: `brightness(${activeEdits.brightness}%) saturate(${activeEdits.saturation}%) contrast(${activeEdits.contrast}%) blur(${activeEdits.blur}px) hue-rotate(${activeEdits.hueRotate}deg) sepia(${activeEdits.sepia}%) invert(${activeEdits.invert}%) grayscale(${activeEdits.grayscale}%)` 
  };

  const VideoPlayerIcons = {
      Play: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>,
      Pause: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1zm4 0a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>,
      VolumeHigh: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>,
      VolumeMute: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" clipRule="evenodd" /><path strokeLinecap="round" strokeLinejoin="round" d="M17 14l2-2m0 0l2-2m-2 2L17 10" /></svg>,
      EnterFullscreen: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 2a1 1 0 011-1h2a1 1 0 010 2H4v2a1 1 0 11-2 0V2zm14 0a1 1 0 011 1v2a1 1 0 11-2 0V4h-2a1 1 0 110-2h3zm-2 15a1 1 0 01-1 1h-2a1 1 0 110-2h2v-2a1 1 0 112 0v3zM4 14a1 1 0 011-1h2a1 1 0 110 2H5v2a1 1 0 11-2 0v-3z" clipRule="evenodd" /></svg>,
      ExitFullscreen: () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M5 2a1 1 0 00-1 1v3a1 1 0 102 0V4h2a1 1 0 100-2H5zm10 0a1 1 0 00-1 1v2h2a1 1 0 100-2h-3V3a1 1 0 00-1-1zm-1 15a1 1 0 100 2h3a1 1 0 001-1v-3a1 1 0 10-2 0v2h-2zm-9 0a1 1 0 100 2h2v-2a1 1 0 10-2 0v2H5a1 1 0 00-1 1z" clipRule="evenodd" /></svg>,
  };

  const warmthOverlayStyle = {
    position: 'absolute' as 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    pointerEvents: 'none' as 'none',
    backgroundColor: activeEdits.warmth > 0 ? 'orange' : 'blue',
    opacity: Math.abs(activeEdits.warmth) / 400,
    mixBlendMode: 'soft-light' as 'soft-light',
  };

  const vignetteOverlayStyle = {
    position: 'absolute' as 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    pointerEvents: 'none' as 'none',
    background: `radial-gradient(circle, rgba(0,0,0,0) 0%, rgba(0,0,0,${activeEdits.vignette / 100}) 100%)`,
  };

  return (
    <div className="w-full flex items-center justify-center">
      {isLoading && <Spinner mode={mode} message={loadingMessage} videoConfig={videoConfig} />}
      {error && !isLoading && (
        <div className={`w-full ${getAspectRatioClass(mode, false, videoConfig)} bg-red-900/20 border-2 border-red-500 rounded-xl flex flex-col items-center justify-center p-8 text-center`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-red-400 mb-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
            <h3 className="text-xl font-semibold text-white">Generation Failed</h3>
            <p className="text-red-300 mt-2">{error}</p>
        </div>
      )}
      {!isLoading && !error && generatedMedia && (
        <div className="w-full flex flex-col items-center gap-4">
          <div className={`w-full relative`}>
            {isVideo ? (
                <div ref={videoContainerRef} onMouseMove={showControls} onMouseLeave={() => { if (controlsTimeoutRef.current) clearTimeout(controlsTimeoutRef.current); setAreControlsVisible(false); }} className={`relative w-full ${aspectRatioClass} bg-black rounded-xl overflow-hidden group`}>
                    <video ref={videoRef} src={generatedMedia} onClick={handleTogglePlay} onPlay={handleVideoPlay} onPause={handleVideoPauseOrEnd} onEnded={handleVideoPauseOrEnd} onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} className="w-full h-full object-contain cursor-pointer" />
                    {!isPlaying && (
                        <button aria-label="Play video" onClick={handleTogglePlay} className="absolute inset-0 flex items-center justify-center w-full h-full bg-black bg-opacity-20 cursor-pointer focus:outline-none">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 md:h-24 md:w-24 text-white/80 drop-shadow-lg transition-transform duration-300 ease-in-out group-hover:scale-110" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                        </button>
                    )}
                    <div className={`absolute bottom-0 left-0 right-0 p-3 bg-gradient-to-t from-black/70 to-transparent transition-opacity duration-300 ${areControlsVisible || !isPlaying || isVideoEditing ? 'opacity-100' : 'opacity-0'}`}>
                        <input type="range" min="0" max={videoDuration || 0} value={videoProgress} onChange={handleSeek} className="w-full h-1.5 bg-white/20 rounded-lg appearance-none cursor-pointer accent-indigo-500"/>
                        <div className="flex items-center justify-between mt-2 text-white">
                            <div className="flex items-center gap-3">
                                <button onClick={handleTogglePlay} className="hover:text-indigo-400 transition-colors">{isPlaying ? <VideoPlayerIcons.Pause /> : <VideoPlayerIcons.Play />}</button>
                                <div className="flex items-center gap-2 group/volume">
                                    <button onClick={handleToggleMute} className="hover:text-indigo-400 transition-colors">{isMuted || volume === 0 ? <VideoPlayerIcons.VolumeMute /> : <VideoPlayerIcons.VolumeHigh />}</button>
                                    <input type="range" min="0" max="1" step="0.05" value={isMuted ? 0 : volume} onChange={handleVolumeChange} className="w-0 group-hover/volume:w-24 h-1.5 bg-white/20 rounded-lg appearance-none cursor-pointer accent-indigo-500 transition-all duration-300" />
                                </div>
                            </div>
                            <div className="flex items-center gap-3 text-sm">
                                <span>{formatTime(videoProgress)} / {formatTime(videoDuration)}</span>
                                <button onClick={handleToggleFullscreen} className="hover:text-indigo-400 transition-colors">{isFullscreen ? <VideoPlayerIcons.ExitFullscreen /> : <VideoPlayerIcons.EnterFullscreen />}</button>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className={`relative w-full ${aspectRatioClass} overflow-hidden rounded-xl shadow-[0_0_50px_rgba(0,0,0,0.5)]`}>
                    <img ref={imageRef} src={generatedMedia} alt="Generated Artwork" crossOrigin="anonymous" style={isEditing ? imageStyle : {}} className={`w-full h-full rounded-xl transition-all duration-300 opacity-100 object-cover`} />
                    {isEditing && (
                      <>
                        <div style={warmthOverlayStyle} />
                        <div style={vignetteOverlayStyle} />
                      </>
                    )}
                </div>
            )}
          </div>

          {isEditing && !isVideo && (
            <EditToolbar 
              activeEdits={activeEdits} 
              onEditChange={handleEditChange} 
              onCommit={handleCommitEdit} 
              onSave={handleSaveChanges} 
              onCancel={resetEditingState} 
              onUndo={handleUndo} 
              onRedo={handleRedo}
              onReset={handleResetFilters}
              canUndo={canUndo} 
              canRedo={canRedo} 
            />
          )}

          {isVideoEditing && (
            <VideoEditToolbar editState={videoEditState} onEditChange={handleVideoEditChange} onApply={handleApplyVideoEdits} onCancel={handleCancelVideoEdits} onReset={handleResetVideoEdits} maxDuration={videoDuration} />
          )}

          <div className="flex flex-col sm:flex-row w-full max-w-lg gap-3">
            <button onClick={handleDownload} disabled={isDownloading || isEditing || isVideoEditing} className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-indigo-500 to-purple-600 text-white font-bold py-3.5 px-6 rounded-xl hover:from-indigo-600 hover:to-purple-700 shadow-xl transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-105 active:scale-95">
              {isDownloading ? (
                <><svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>Exporting...</>
              ) : (
                <><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" /></svg>Export Artwork</>
              )}
            </button>
            {!isVideo && !isEditing && !isVideoEditing && (
              <button onClick={handleStartEditing} className="w-full sm:w-auto flex items-center justify-center gap-2 bg-gray-700 text-white font-bold py-3.5 px-6 rounded-xl hover:bg-gray-600 transition-all border border-gray-600 active:scale-95">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
                Edit Design
              </button>
            )}
             {isVideo && !isEditing && !isVideoEditing && (
              <button onClick={handleStartVideoEditing} className="w-full sm:w-auto flex items-center justify-center gap-2 bg-gray-700 text-white font-bold py-3.5 px-6 rounded-xl hover:bg-gray-600 transition-all border border-gray-600 active:scale-95">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
                Post-Production
              </button>
            )}
          </div>
        </div>
      )}
      {!isLoading && !error && !generatedMedia && <Placeholder mode={mode} videoConfig={videoConfig} onUpload={setGeneratedMedia} />}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { GenerationMode, VideoGenerationConfig, VideoStyle, ImageStyle, ImageQuality } from '../types';

const getStyleInstruction = (style: ImageStyle, customStyle: string): string => {
  if (style === ImageStyle.DEFAULT) {
    return '';
  }
  if (style === ImageStyle.CUSTOM) {
    return customStyle ? ` The image must be in the following style: ${customStyle}.` : '';
  }
  if (style === ImageStyle.GOOGLE) {
    return ' The image must be in the Google style: vibrant, primary colors, clean lines, modern, minimalist, with a playful and friendly touch. Flat design with subtle shadows.';
  }
  return ` The image must be in a ${style.toLowerCase()} style.`;
};

const constructPrompt = (prompt: string, mode: GenerationMode): string => {
  switch (mode) {
    case GenerationMode.THUMBNAIL:
      return `Create a VIRAL, high-energy YouTube thumbnail for: '${prompt}'. 
      EXPERT DESIGN REQUIREMENTS:
      - SUBJECT: Center or Rule-of-Thirds placement of a highly expressive subject. If a person is mentioned, they must have exaggerated, shocked, or intense emotions.
      - LIGHTING: Professional 3-point studio lighting with strong rim lights (blue/cyan or red/orange) and dramatic shadows.
      - TEXT: Big, bold, 3D block letters with neon glows, heavy outlines, and significant drop shadows. Use contrasting colors like Yellow/Black or Red/White.
      - BACKGROUND: Busy but focused background with a dark gradient, motion blur, and atmospheric effects (smoke, sparks, or light streaks).
      - ENGAGEMENT HOOKS: Include subtle visual cues like bright green growth arrows, red circles, or "zoom-in" effects where appropriate.
      - POST-PROCESSING: Ultra-vibrant colors, maximum sharpness, "Photoshop-polished" look, and cinematic 4K detail. 
      - ASPECT RATIO: 16:9 optimized for CTR.`;
    case GenerationMode.CARTOON:
      return `A professional character design in a modern 3D cartoon style (reminiscent of high-budget animated films). Detailed textures, expressive features, and soft, warm lighting. Square aspect ratio. Subject: ${prompt}`;
    case GenerationMode.STORY_IMAGE:
      return `A cinematic book-cover style illustration for this story: '${prompt}'. Atmospheric, moody, and highly detailed. Focus on the core emotional moment. 9:16 vertical ratio. No text on image.`;
    case GenerationMode.SOCIAL:
      return `A sleek, high-end professional social media graphic for: '${prompt}'. Modern typography, clean alignment, premium color palette (Gold/Black, Blue/White, or Minimalist), and elegant background textures. Square aspect ratio.`;
    case GenerationMode.VERTICAL_STORY:
      return `A dynamic vertical story layout for: '${prompt}'. High-contrast title at the top, clear call-to-action area, and a background that uses professional photography or abstract gradients. 9:16 vertical ratio.`;
    default:
      return prompt;
  }
};

export const generateImage = async (
  prompt: string, 
  mode: GenerationMode, 
  imageStyle: ImageStyle, 
  customImageStyle: string,
  quality: ImageQuality = ImageQuality.STANDARD
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let fullPrompt = constructPrompt(prompt, mode);
  const styleInstruction = getStyleInstruction(imageStyle, customImageStyle);
  fullPrompt += styleInstruction;

  let aspectRatio: '16:9' | '1:1' | '9:16' = '16:9';
  if (mode === GenerationMode.CARTOON || mode === GenerationMode.SOCIAL) {
    aspectRatio = '1:1';
  } else if (mode === GenerationMode.VERTICAL_STORY || mode === GenerationMode.STORY_IMAGE) {
    aspectRatio = '9:16';
  }

  if (quality === ImageQuality.STANDARD) {
    const response = await ai.models.generateImages({
      model: 'imagen-4.0-generate-001',
      prompt: fullPrompt,
      config: {
        numberOfImages: 1,
        outputMimeType: 'image/jpeg',
        aspectRatio: aspectRatio,
      },
    });

    if (response.generatedImages && response.generatedImages.length > 0) {
      const base64ImageBytes = response.generatedImages[0].image.imageBytes;
      return `data:image/jpeg;base64,${base64ImageBytes}`;
    } else {
      throw new Error("No image was generated by the API.");
    }
  } else {
    const imageSize = quality === ImageQuality.HIGH ? "2K" : "4K";
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: fullPrompt }] },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio === '16:9' ? '16:9' : aspectRatio === '9:16' ? '9:16' : '1:1',
          imageSize: imageSize
        },
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No high-quality image was generated by the API.");
  }
};

export const generateVideo = async (
  prompt: string, 
  config: VideoGenerationConfig, 
  onProgress?: (status: string) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const stylePrompt = config.style === VideoStyle.DEFAULT ? 'animated' : config.style;
  const fullPrompt = `A high-quality, ${stylePrompt} style video of '${prompt}'. The video should be approximately ${config.duration} seconds long.`;

  if (onProgress) onProgress("Sending request to Gemini...");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: fullPrompt,
    config: {
      numberOfVideos: 1,
      aspectRatio: config.aspectRatio,
      resolution: '720p',
    }
  });

  if (onProgress) onProgress("Video generation started...");

  const POLL_INTERVAL = 5000;
  let elapsedSeconds = 0;

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));
    elapsedSeconds += POLL_INTERVAL / 1000;

    if (onProgress) {
        onProgress(`Rendering video... (~${elapsedSeconds}s elapsed)`);
    }

    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  if (onProgress) onProgress("Finalizing video...");

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (downloadLink) {
    return `${downloadLink}&key=${process.env.API_KEY}`;
  } else {
    throw new Error("No video was generated by the API or the operation failed.");
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GenerationMode, VideoGenerationConfig, VideoFilter } from '../types';

interface ImageDisplayProps {
  isLoading: boolean;
  loadingMessage: string;
  generatedMedia: string | null;
  setGeneratedMedia: (url: string | null) => void;
  error: string | null;
  mode: GenerationMode;
  videoConfig?: VideoGenerationConfig;
}

interface EditState {
  brightness: number;
  saturation: number;
  contrast: number;
  exposure: number;
  highlights: number;
  shadows: number;
  blur: number;
  hueRotate: number;
  sepia: number;
  invert: number;
  grayscale: number;
  vignette: number;
  warmth: number;
  isCroppedToSquare: boolean;
}

interface VideoEditState {
  trimStart: number;
  trimEnd: number;
  playbackRate: number;
  filter: VideoFilter;
}

const filterMap: Record<VideoFilter, string> = {
  [VideoFilter.NONE]: 'none',
  [VideoFilter.GRAYSCALE]: 'grayscale(100%)',
  [VideoFilter.SEPIA]: 'sepia(100%)',
  [VideoFilter.INVERT]: 'invert(100%)',
  [VideoFilter.VINTAGE]: 'sepia(60%) contrast(75%) brightness(120%) saturate(120%)',
  [VideoFilter.DREAMY]: 'saturate(150%) contrast(110%) brightness(110%) blur(0.5px)',
};

const INITIAL_EDIT_STATE: EditState = { 
  brightness: 100, 
  saturation: 100, 
  contrast: 100,
  exposure: 0,
  highlights: 100,
  shadows: 100,
  blur: 0,
  hueRotate: 0,
  sepia: 0,
  invert: 0,
  grayscale: 0,
  vignette: 0,
  warmth: 0,
  isCroppedToSquare: false 
};

const getAspectRatioClass = (mode: GenerationMode, isCroppedToSquare = false, videoConfig?: VideoGenerationConfig) => {
    if (isCroppedToSquare) return 'aspect-square';
    switch (mode) {
        case GenerationMode.CARTOON:
        case GenerationMode.SOCIAL:
            return 'aspect-square';
        case GenerationMode.VERTICAL_STORY:
        case GenerationMode.STORY_IMAGE:
            return 'aspect-[9/16]';
        case GenerationMode.VIDEO:
             if (videoConfig) {
                switch (videoConfig.aspectRatio) {
                    case '9:16': return 'aspect-[9/16]';
                    case '1:1': return 'aspect-square';
                    case '16:9':
                    default: return 'aspect-video';
                }
            }
            return 'aspect-video';
        case GenerationMode.THUMBNAIL:
        default:
            return 'aspect-video';
    }
};

